local function getChildWindow(window, name, type)
    local child = window:getChildWindow(name, type)
    if not child then
        error("SumRechargeMain must have" .. name .. " child window.")
    end
    return child
end

local UISumRechargeMain = class("UISumRechargeMain", IGUILayout)

function UISumRechargeMain:onLoad()
    local name = string.gsub(self.__name, ".json", "-")
    self.btnIcon = getChildWindow(self, name .. "Icon", GUIType.Button)
    self.ivEffect = getChildWindow(self, name .. "Effect", GUIType.StaticImage)
    self.btnIcon:registerEvent(GUIEvent.ButtonClick, function()
        GUISumRechargeLayout:show()
    end)
end

function UISumRechargeMain:onShow(id)
    if not id then
        return
    end
    local config = SumRechargeConfig:getSumRecharge(id)
    if not config then
        return
    end
    self.btnIcon:SetNormalImage(config.MainIcon)
    self.btnIcon:SetPushedImage(config.MainIcon)
    self.ivEffect:SetEffectName(config.MainIconEffect)
end

function UISumRechargeMain:registerEvents()
    self:registerDataCallBack("ShowSumRecharge", function(data)
        local id = data:getParam("Id")
        local config = SumRechargeConfig:getSumRecharge(id)
        if config then
            if self.__name ~= config.MainUIName then
                self:reload(config.MainUIName)
            end
            self:show(id)
        else
            self:hide()
        end
    end, DataBuilderProcessor)
end

function UISumRechargeMain:reload(name)
    GUIManager:removeLayout(self)
    GUIManager:destroyGUIWindow(self.root)
    for key, value in pairs(self) do
        if type(value) == "userdata" then
            self[key] = nil
        end
    end
    self.__name = name
    self.parent = GUIManager:getMainControl()
    self:load()
end

return UISumRechargeMain